def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.0:
            if ratio > 1.5:
                priority = (ratio - 1.5)**4 * 200 + 30
                if ratio > 2.5:
                    priority += (ratio - 2.5)**2 * 100
            else:
                priority = (ratio - 1.0) * 250 + 20
                for j in range(1, 4):
                    priority += ((-1)**j) * (ratio ** (j * 1.5)) * 5 * j
        else:
            exp_accum = 0
            for k in range(1, 10):
                factor = ((-1)**(k+1)) * (ratio**(k*1.1)) / (k*0.8)
                if k % 3 == 0:
                    factor *= 1.7
                exp_accum += factor
            priority += abs(exp_accum)
            if capacity < item * 2:
                priority *= 3
            log_diff = np.log(capacity + 4) - np.log(item + 1)
            if log_diff > 0:
                priority += 10 / log_diff
            else:
                priority += 35
            mod2 = capacity % 2
            mod3 = capacity % 3
            mod7 = capacity % 7
            if mod7 == 0:
                priority += 1.2
            elif mod3 == 0:
                priority += 0.8
            elif mod2 == 0:
                priority += 0.5
            else:
                priority -= 0.4
            if ratio < 0.4:
                for m in range(1, 6):
                    term = ((-1)**(m+1)) * (ratio**(m*2.5)) * (m*0.7)
                    if m == 4 and capacity > item * 7:
                        term *= 1.6
                    priority += term
            if capacity > 6 * item:
                priority -= 3.0
            if capacity % 10 == 0 and ratio < 0.55:
                priority -= 1.0
            if capacity > item * 12:
                for n in range(2, 7):
                    sqrt_n = np.sqrt(n)
                    power_term = ratio ** (1 / n)
                    sign_term = (-1) ** (n + 1)
                    priority += sqrt_n * power_term * sign_term * (n * 0.3)
            if priority > 60:
                priority = 60 + np.log(priority - 59) * 1.5
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
